function solve(nums) {
    const absArr = nums.map(x => Math.abs(x));
    absArr.sort((a, b) => a - b);
    let total = 0;
    const n = absArr.length;
    for (let i = 0; i < n; i++) {
        const target = 2 * absArr[i];
        let low = i + 1;
        let high = n - 1;
        let j = i;
        while (low <= high) {
            const mid = Math.floor((low + high) / 2);
            if (absArr[mid] <= target) {
                j = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        if (j > i) {
            total += (j - i);
        }
    }
    return total;
}
